#include<cstdio>
#include<algorithm>
#define N 1000005
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define Loc(x) ((x-1)/sn)
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<21,stdin),p1==p2)?EOF:*p1++)
char buf[1<<23],*p1=buf,*p2=buf;
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch>='0'&&ch<='9')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();return res;
}
inline void write(int X){if(X>9) write(X/10);putchar(X%10+'0');}
int cnt[N],a[N],sn,L=1,R,ans[N],res;
struct node{int l,r,n;}t[N];
inline bool cmp(node x,node y){int lx=Loc(x.l),ly=Loc(y.l);return (lx<ly)?1:((lx>ly)?0:(x.r<y.r)^(lx&1));}
inline void del(int k){cnt[a[k]]--;res-=(!cnt[a[k]]);}
int main()
{
	int n=read();rep(1,n,i)a[i]=read();
	int m=read();rep(1,m,i)t[i].l=read(),t[i].r=read(),t[i].n=i;
	sn=1780;sort(t+1,t+m+1,cmp);int L=0,R=0;rep(1,m,i)
	{
		while(L<t[i].l)res-=!(--cnt[a[L++]]);
		while(R>t[i].r)res-=!(--cnt[a[R--]]);
		while(L>t[i].l)res+=(++cnt[a[--L]]==1);
		while(R<t[i].r)res+=(++cnt[a[++R]]==1);
		ans[t[i].n]=res;
	}
	rep(1,m,i)write(ans[i]),puts("");
}
